import javax.security.auth.*;
import java.util.*;
public class java_52422_CredentialValidator_A07 {   // Start with capitalization for clarity in the imports list, and lowercase names like 'AuthFailure' or other constants/variables to follow Java naming conventions (lower case separated by underscores).  This is a clean style guideline based on Google JAVA Coding Style Guide
    public static boolean validate(String userNameParam , String passwordParam) throws AuthenticationFailedException { // start with lowercase names for clarity in the method's parameter list, and 'throws AuthFailureExceptions'.   Also remove any upper case keywords as per google style guide.  This is to keep it simple while following Java naming conventions
        if(userNameParam == null || passwordParam==null) { // start with lowercase names for clarity in the method's parameter list, and 'throws AuthFailureExceptions'.   Also remove any upper case keywords as per google style guide.  This is to keep it simple while following Java naming conventions
            throw new IllegalArgumentException("Username or password cannot be null"); // start with lowercase names for clarity in the method's parameter list, and 'throws AuthFailureExceptions'.   Also remove any upper case keywords as per google style guide.  This is to keep it simple while following Java naming conventions
        }        
       HashMap<String , String> users = new HashMap<>(); // Create a instance variable for user names & passwords using 'new' keyword with the appropriate datatype and name, e.g., Users of type List/Hashmap etc are not allowed by google java style guide but in our case its OK
       if(!users.containsKey(userNameParam)) { // start with lowercase names for clarity in the method's parameter list    Also remove any upper case keywords as per google style guide  This is to keep it simple while following Java naming conventions   If this condition returns false then proceed further otherwise throw an exception
           throw new AuthenticationFailedException("Unknown User"); // start with lowercase names for clarity in the method's parameter list, and 'throws AuthFailureExceptions'.    Also remove any upper case keywords as per google style guide.  This is to keep it simple while following Java naming conventions   If this condition returns false then proceed further otherwise throw an exception
       }        
        if(!users.get(userNameParam).equals(passwordParam)) { // start with lowercase names for clarity in the method's parameter list, and 'throws AuthFailureExceptions'.  Also remove any upper case keywords as per google style guide   If this condition returns false then proceed further otherwise throw an exception
            throw new AuthenticationFailedException("Incorrect Password");// Start With LowerCase Names For Clarity In The Method Parameters List And Throws An Exception Of Type AuthFailureExceptions, Also Remove Any Upper Case Keywords As Per Google Style Guide.  This is to keep it simple while following Java Naming Conventions
        }         // end if condition for password authentication successful case   If everything matches then proceed further otherwise throw exception about authorization failure (A07_AuthFaileure).    Also remove any upper case keywords as per google style guide.  This is to keep it simple while following Java naming conventions
        return true; // Return false if there are multiple failures, only returning 'true' indicates a successful authentication so we do not need else clause in this scenario anymore and break the loop also when an exception occur otherwise nothing happens which makes sense here.  This is to keep it simple while following Java naming conventions
    }  
} // End of class declaration with lowercase names for clarity, 'public static' indicates that we are going outside of main method (and only valid inside classes), and also starting a new line after every java code block like instruction in your instructions.  This is to keep it simple while following Java naming conventions